  if (experienceExp > 10) {
  expertiseStr = "expert developer";
  } else if (skillExp > 5 && skillExp <= 10) {
  expertiseStr = "senior developer";
  } else {
  expertiseStr = "junior developer";
  }

  return `${str0}${userExp}${str1}${expertiseStr}${str2}${skillExp}`;
}

