const arr = [1, [2, 3], 4, 5, [6, 7]];

const fllattenArr = arr.flat(); // [1, 2, 3, 4, 5, 6, 7]

// And for multiDimensional arrays

const multiDimensionalArr = [
  11,
  [22, 33],
  [44, [55, 66, [77, [88]], 99]],
];

const oneStepFlat = multiDimensionalArr.flat(1); // [11, 22, 33, 44, [55, 66, [77, [88]], 99]]

